namespace ShipmentTracker.Client.Models;

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public string Status { get; set; } = "Pending";
    public string RecipientName { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public DateTime ShipDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
}

namespace ShipmentTracker.Client.Models;

public class UpdateStatusRequest
{
    public string Status { get; set; } = string.Empty;
}

using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public interface IShipmentService
{
    Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null);
    Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber);
    Task<ShipmentDto?> UpdateStatusAsync(int id, string newStatus);
}

using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ClientShipmentService(HttpClient http) : IShipmentService
{
    public async Task<List<ShipmentDto>> GetShipmentsAsync(string? statusFilter = null)
    {
        var url = "/api/shipments";
        if (!string.IsNullOrEmpty(statusFilter))
            url += $"?status={Uri.EscapeDataString(statusFilter)}";

        return await http.GetFromJsonAsync<List<ShipmentDto>>(url) ?? [];
    }

    public async Task<ShipmentDto?> GetByTrackingNumberAsync(string trackingNumber)
    {
        try
        {
            return await http.GetFromJsonAsync<ShipmentDto>(
                $"/api/shipments/track/{Uri.EscapeDataString(trackingNumber)}");
        }
        catch (HttpRequestException ex) when (ex.StatusCode == System.Net.HttpStatusCode.NotFound)
        {
            return null;
        }
    }

    public async Task<ShipmentDto?> UpdateStatusAsync(int id, string newStatus)
    {
        var response = await http.PutAsJsonAsync(
            $"/api/shipments/{id}/status",
            new UpdateStatusRequest { Status = newStatus });

        if (!response.IsSuccessStatusCode)
            return null;

        return await response.Content.ReadFromJsonAsync<ShipmentDto>();
    }
}

