using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Pages;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Components;
using ShipmentTracker.Components.Account;
using ShipmentTracker.Data;
using ShipmentTracker.Services;

builder.Services.AddSingleton<IEmailSender<ApplicationUser>, IdentityNoOpEmailSender>();

builder.Services.AddScoped<IShipmentService, ServerShipmentService>();

var app = builder.Build();

// Apply pending migrations and seed data automatically in development
using (var scope = app.Services.CreateScope())
{
    var db = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
    db.Database.Migrate();
}

// Shipment API endpoints
var shipments = app.MapGroup("/api/shipments").RequireAuthorization();

shipments.MapGet("/", async (string? status, IShipmentService svc) =>
    Results.Ok(await svc.GetShipmentsAsync(status)));

shipments.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService svc) =>
{
    var shipment = await svc.GetByTrackingNumberAsync(trackingNumber);
    return shipment is null ? Results.NotFound() : Results.Ok(shipment);
}).AllowAnonymous();

shipments.MapPut("/{id:int}/status", async (int id, ShipmentTracker.Client.Models.UpdateStatusRequest request, IShipmentService svc) =>
