arguments.file_text:
@page "/shipments"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Dispatcher Dashboard</h1>

<div class="row mb-3">
    <div class="col-auto">
        <label class="form-label fw-bold">Filter by status:</label>
    </div>
    <div class="col-auto">
        <select class="form-select" @bind="selectedStatus" @bind:after="LoadShipments">
            <option value="">All</option>
            <option value="Pending">Pending</option>
            <option value="InTransit">In Transit</option>
            <option value="Delivered">Delivered</option>
            <option value="Delayed">Delayed</option>
        </select>
    </div>
</div>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (shipments.Count == 0)
{
    <div class="alert alert-info">No shipments found.</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Ship Date</th>
                    <th>Est. Delivery</th>
                    <th>Status</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var s in shipments)
                {
                    <tr>
                        <td><code>@s.TrackingNumber</code></td>
                        <td>@s.Origin</td>
                        <td>@s.Destination</td>
                        <td>@s.RecipientName</td>
                        <td>@s.ShipDate.ToString("yyyy-MM-dd")</td>
                        <td>@(s.EstimatedDelivery?.ToString("yyyy-MM-dd") ?? "—")</td>
                        <td><span class="badge @StatusBadge(s.Status)">@FormatStatus(s.Status)</span></td>
                        <td>
                            @if (s.Status != "Delivered")
                            {
                                <select class="form-select form-select-sm d-inline-block w-auto"
                                        value="@s.Status"
                                        @onchange="e => OnStatusChanged(s, e)">
                                    <option value="Pending">Pending</option>
                                    <option value="InTransit">In Transit</option>
                                    <option value="Delayed">Delayed</option>
                                    <option value="Delivered">Delivered</option>
                                </select>
                            }
                            else
                            {
                                <span class="text-muted">@(s.ActualDelivery?.ToString("yyyy-MM-dd") ?? "")</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(updateMessage))
{
    <div class="alert alert-success alert-dismissible mt-3">
        @updateMessage
        <button type="button" class="btn-close" @onclick="() => updateMessage = null"></button>
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string selectedStatus = "";
    private string? updateMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        shipments = await ShipmentService.GetShipmentsAsync(
            string.IsNullOrEmpty(selectedStatus) ? null : selectedStatus);
    }

    private async Task OnStatusChanged(ShipmentDto shipment, ChangeEventArgs e)
    {
        var newStatus = e.Value?.ToString();
        if (string.IsNullOrEmpty(newStatus) || newStatus == shipment.Status)
            return;

        var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
        if (updated is not null)
        {
            shipment.Status = updated.Status;
            shipment.ActualDelivery = updated.ActualDelivery;
            updateMessage = $"Shipment {shipment.TrackingNumber} updated to {FormatStatus(newStatus)}.";
        }
    }

    private static string StatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "InTransit" => "In Transit",
        _ => status
    };
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260001)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="OnKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Search
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found for tracking number <strong>@searchedNumber</strong>. Please verify and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
            <span class="badge @StatusBadge(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>

                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Ship Date</dt>
                        <dd>@shipment.ShipDate.ToString("MMMM d, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                @shipment.EstimatedDelivery.Value.ToString("MMMM d, yyyy")
                            }
                            else
                            {
                                <span class="text-muted">Not available</span>
                            }
                        </dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
