@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g. SHP-20260001)"
                   @bind="trackingNumber" @bind:event="oninput"
                   @onkeydown="OnKeyDown" />
            <button class="btn btn-primary" @onclick="Search" disabled="@isSearching">
                @if (isSearching)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Search
            </button>
        </div>
    </div>
</div>

@if (searched && shipment is null)
{
    <div class="alert alert-warning">
        No shipment found for tracking number <strong>@searchedNumber</strong>. Please verify and try again.
    </div>
}

@if (shipment is not null)
{
    <div class="card">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">Shipment <code>@shipment.TrackingNumber</code></h5>
            <span class="badge @StatusBadge(shipment.Status) fs-6">@FormatStatus(shipment.Status)</span>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Description</dt>
                        <dd>@shipment.Description</dd>

                        <dt>Recipient</dt>
                        <dd>@shipment.RecipientName</dd>

                        <dt>Origin</dt>
                        <dd>@shipment.Origin</dd>

                        <dt>Destination</dt>
                        <dd>@shipment.Destination</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Ship Date</dt>
                        <dd>@shipment.ShipDate.ToString("MMMM d, yyyy")</dd>

                        <dt>Estimated Delivery</dt>
                        <dd>
                            @if (shipment.EstimatedDelivery.HasValue)
                            {
                                @shipment.EstimatedDelivery.Value.ToString("MMMM d, yyyy")
                            }
                            else
                            {
                                <span class="text-muted">Not available</span>
                            }
                        </dd>

                        @if (shipment.ActualDelivery.HasValue)
                        {
                            <dt>Actual Delivery</dt>
                            <dd class="text-success fw-bold">@shipment.ActualDelivery.Value.ToString("MMMM d, yyyy")</dd>
                        }
                    </dl>
                </div>
            </div>

            @* Status progress bar *@
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @ProgressBarClass(shipment.Status)"
                         role="progressbar"
                         style="width: @ProgressPercent(shipment.Status)%"
                         aria-valuenow="@ProgressPercent(shipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @FormatStatus(shipment.Status)
                    </div>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string trackingNumber = "";
    private string searchedNumber = "";
    private ShipmentDto? shipment;
    private bool searched;
    private bool isSearching;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber))
            return;

        isSearching = true;
        searchedNumber = trackingNumber.Trim();
        shipment = await ShipmentService.GetByTrackingNumberAsync(searchedNumber);
        searched = true;
        isSearching = false;
    }

    private async Task OnKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string StatusBadge(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark",
        _ => "bg-secondary"
    };

    private static string FormatStatus(string status) => status switch
    {
        "InTransit" => "In Transit",
        _ => status
    };

    private static string ProgressBarClass(string status) => status switch
    {
        "Pending" => "bg-secondary",
        "InTransit" => "bg-primary progress-bar-striped progress-bar-animated",
        "Delivered" => "bg-success",
        "Delayed" => "bg-warning text-dark progress-bar-striped",
        _ => "bg-secondary"
    };

    private static int ProgressPercent(string status) => status switch
    {
        "Pending" => 15,
        "InTransit" => 60,
        "Delivered" => 100,
        "Delayed" => 45,
        _ => 0
    };
}

